import { _decorator, Component } from 'cc';

const { ccclass, property } = _decorator;

@ccclass('EnemyFinder')
export class EnemyFinder extends Component {

    @property
    updateInterval = 30;

    private team = 0;

    resetForSpawn(team: number) {
        this.team = team;
    }

    setTeam(team: number) {
        this.team = team;
    }

    getTeam() {
        return this.team;
    }
}
